149	// Restores x1..x31 and PC into the QEMU vCPU via the gdbstub at `port`,
150	// then continues. Caller is responsible for waitpid().
151	inline void restore_state_via_gdbstub(uint16_t port,
152	                                      const hybrid_state_v1& state,
153	                                      pid_t child_pid = -1)
154	{
155	  spdlog::info("hybrid handback: connecting to gdbstub on tcp::{}", port);
156	  const int fd = detail::connect_loopback(port, std::chrono::seconds(5),
157	                                          child_pid);
158	  spdlog::info("hybrid handback: connected, restoring state");
159	  gdbstub::Session sess{fd};
160	
161	  for (unsigned i = 1; i < 32; ++i) {
162	    auto reply = sess.send_command(gdbstub::encode_p_body(i, state.gpr[i]));
163	    if (reply != "OK")
164	      throw std::runtime_error(
165	        "gdbstub: P packet for x" + std::to_string(i) + " replied " + reply);
166	  }
167	
168	  // RV64 GDB register layout: x0..x31 = 0..31, pc = 32.
169	  auto reply = sess.send_command(gdbstub::encode_p_body(32, state.pc));
170	  if (reply != "OK")
171	    throw std::runtime_error("gdbstub: P32 (pc) replied " + reply);
172	
173	  spdlog::info("hybrid handback: continuing target");
174	  sess.cont();
175	}
