177	// Top-level: spawns QEMU, restores state, waits for exit, returns exit
178	// status (or 128 + signal for abnormal termination).
179	inline auto run_qemu_handback(const std::string& qemu_binary,
180	                              const std::string& elf_path,
181	                              const hybrid_state_v1& state,
182	                              const std::string& shared_mem_path = {},
183	                              uint64_t shared_mem_size = 0) -> int
184	{
185	  const auto port = detail::pick_free_port();
186	  spdlog::info("hybrid handback: spawning {} -gdb tcp::{} -S",
187	               qemu_binary, port);
188	  const pid_t pid = detail::spawn_qemu(qemu_binary, elf_path, port,
189	                                       shared_mem_path, shared_mem_size);
190	
191	  try {
192	    restore_state_via_gdbstub(port, state, pid);
193	  } catch (const detail::ChildExitedDuringConnect& d) {
194	    return d.status;
195	  } catch (...) {
196	    ::kill(pid, SIGKILL);
197	    int wstat = 0;
198	    ::waitpid(pid, &wstat, 0);
199	    throw;
200	  }
201	
202	  int wstat = 0;
203	  if (::waitpid(pid, &wstat, 0) < 0)
204	    throw std::runtime_error(std::string{"waitpid: "}
205	                             + std::strerror(errno));
206	  if (WIFEXITED(wstat)) return WEXITSTATUS(wstat);
207	  if (WIFSIGNALED(wstat)) return 128 + WTERMSIG(wstat);
208	  return -1;
209	}
