290	static int andes_ace_get_reg(CPUState *cs, int reg_n)
291	{
292	    RISCVCPU *cpu = RISCV_CPU(cs);
293	    CPURISCVState *env = &cpu->env;
294	    unsigned int ByteSize = 0;
295	    unsigned int reg_idx = 0;
296	    char *type_name = NULL;
297	    uint32_t curr_reg_no = 0;
298	    AceAcrInfo *acr_info_list = env->ace_acr_info_list;
299	    unsigned int grp_idx = 0;
300	    uint64_t *value;
301	    uint32_t value_len;
302	
303	    if (acr_info_list == NULL) {
304	        return 0;
305	    }
306	
307	    /* Get acr info by ACR register number */
308	    for (unsigned int i = 0; i < env->ace_acracm_reg_number; i++) {
309	        if ((acr_info_list->num + curr_reg_no) >= reg_n + 1) {
310	            reg_idx = reg_n - curr_reg_no;
311	            grp_idx = acr_info_list->idx;
312	            type_name = acr_info_list->name;
313	            unsigned int acr_width = acr_info_list->width;
314	            ByteSize =
315	                (acr_width % 8 == 0) ? acr_width / 8 : (acr_width / 8) + 1;
316	            break;
317	        }
318	        curr_reg_no += acr_info_list->num;
319	        acr_info_list++;
320	    }
321	    if (type_name == NULL) {
322	        qemu_printf("Cannot find gdb ACE register number %d\n", reg_n);
323	        return -1;
324	    }
325	
326	    value = qemu_ace_agent_get_register(env, grp_idx, reg_idx, &value_len);
327	    env->ace_acr_value = (unsigned char *)value;
328	    return ByteSize;
329	}
