453	static GDBFeature *ricsv_gen_dynamic_vector_feature(CPUState *cs, int base_reg)
454	{
455	    RISCVCPU *cpu = RISCV_CPU(cs);
456	    int bitsize = cpu->cfg.vlenb << 3;
457	    GDBFeatureBuilder builder;
458	    int i;
459	
460	    gdb_feature_builder_init(&builder, &cpu->dyn_vreg_feature,
461	                             "org.gnu.gdb.riscv.vector", "riscv-vector.xml",
462	                             base_reg);
463	
464	    /* First define types and totals in a whole VL */
465	    for (i = 0; i < ARRAY_SIZE(vec_lanes); i++) {
466	        int count = bitsize / vec_lanes[i].size;
467	        gdb_feature_builder_append_tag(
468	            &builder, "<vector id=\"%s\" type=\"%s\" count=\"%d\"/>",
469	            vec_lanes[i].id, vec_lanes[i].gdb_type, count);
470	    }
471	
472	    /* Define unions */
473	    gdb_feature_builder_append_tag(&builder, "<union id=\"riscv_vector\">");
474	    for (i = 0; i < ARRAY_SIZE(vec_lanes); i++) {
475	        gdb_feature_builder_append_tag(&builder,
476	                                       "<field name=\"%c\" type=\"%s\"/>",
477	                                       vec_lanes[i].suffix, vec_lanes[i].id);
478	    }
479	    gdb_feature_builder_append_tag(&builder, "</union>");
480	
481	    /* Define vector registers */
482	    for (i = 0; i < 32; i++) {
483	        gdb_feature_builder_append_reg(&builder, g_strdup_printf("v%d", i),
484	                                       bitsize, i, "riscv_vector", "vector");
485	    }
486	
487	    gdb_feature_builder_end(&builder);
488	
489	    return &cpu->dyn_vreg_feature;
490	}
