493	{
494	    RISCVCPUClass *mcc = RISCV_CPU_GET_CLASS(cs);
495	    RISCVCPU *cpu = RISCV_CPU(cs);
496	    CPURISCVState *env = &cpu->env;
497	    if (env->misa_ext & RVD) {
498	        gdb_register_coprocessor(cs, riscv_gdb_get_fpu, riscv_gdb_set_fpu,
499	                                 gdb_find_static_feature("riscv-64bit-fpu.xml"),
500	                                 0);
501	    } else if (env->misa_ext & RVF) {
502	        gdb_register_coprocessor(cs, riscv_gdb_get_fpu, riscv_gdb_set_fpu,
503	                                 gdb_find_static_feature("riscv-32bit-fpu.xml"),
504	                                 0);
505	    }
506	    if (cpu->cfg.ext_zve32x) {
507	        gdb_register_coprocessor(cs, riscv_gdb_get_vector,
508	                                 riscv_gdb_set_vector,
509	                                 ricsv_gen_dynamic_vector_feature(cs, cs->gdb_num_regs),
510	                                 0);
511	    }
512	    switch (mcc->misa_mxl_max) {
513	    case MXL_RV32:
514	        gdb_register_coprocessor(cs, riscv_gdb_get_virtual,
515	                                 riscv_gdb_set_virtual,
516	                                 gdb_find_static_feature("riscv-32bit-virtual.xml"),
517	                                 0);
518	        break;
519	    case MXL_RV64:
520	    case MXL_RV128:
521	        gdb_register_coprocessor(cs, riscv_gdb_get_virtual,
522	                                 riscv_gdb_set_virtual,
523	                                 gdb_find_static_feature("riscv-64bit-virtual.xml"),
524	                                 0);
525	        break;
526	    default:
527	        g_assert_not_reached();
528	    }
529	
530	    if (cpu->cfg.ext_zicsr) {
531	        gdb_register_coprocessor(cs, riscv_gdb_get_csr, riscv_gdb_set_csr,
532	                                 riscv_gen_dynamic_csr_feature(cs, cs->gdb_num_regs),
533	                                 0);
534	    }
535	    GDBFeature *feature = riscv_gen_dynamic_ace_xml(cs, cs->gdb_num_regs);
536	    if (feature && feature->num_regs != 0) {
537	        gdb_register_coprocessor(cs, riscv_gdb_get_ace, riscv_gdb_set_ace,
538	                                 feature,
539	                                 0);
540	    }
541	}
